import pytest

MAX_BODY_LEN = 5000

def test_message_body_at_maximum_character_boundary(auth_client, provider_id):
    base_payload = {"subject": "BVA Test", "recipient_id": provider_id}

    at_limit_payload = {**base_payload, "body": "A" * MAX_BODY_LEN}
    r_at = auth_client.post("/messages", json=at_limit_payload)
    assert r_at.status_code == 201
    assert r_at.json()["status"] == "stored"

    over_limit_payload = {**base_payload, "body": "A" * (MAX_BODY_LEN + 1)}
    r_over = auth_client.post("/messages", json=over_limit_payload)
    assert r_over.status_code == 422
    assert r_over.json().get("error_code") == "BODY_TOO_LONG"
